import React, { useEffect, useState } from 'react';
import PromoBanner from '../components/PromoBanner';

import './Home.css';
import { useNavigate } from 'react-router-dom';

const featuredPromotions = [
  { id: 1, title: "Buy 2 Milo, Get 1 Free", description: "Valid this weekend only!" },
  { id: 2, title: "25% Off All Fans", description: "Cool your home at less cost." },
];

function Home() {
  const [selectedStore, setSelectedStore] = useState(() => localStorage.getItem('selectedStore') || '');
  const navigate = useNavigate();

  const handleStoreChange = (e) => {
    const store = e.target.value;
    setSelectedStore(store);
    localStorage.setItem('selectedStore', store);
  };

  useEffect(() => {
    const saved = localStorage.getItem('selectedStore');
    if (saved) setSelectedStore(saved);
  }, []);

  const goToProduct = (productId) => {
    navigate(`/product/${productId}`);
  };

  return (
    <div className="home-page">
      <PromoBanner />
      {/* Store Selector */}
      <div className="store-selector">
        <label htmlFor="store">Select Your Preferred Store:</label>
        <select id="store" value={selectedStore} onChange={handleStoreChange}>
          <option value="">-- Select Store --</option>
          <option value="Agip Road Rumueme">Agip Road Rumueme</option>
          <option value="Trans Amadi Industrial Layout">Trans Amadi Industrial Layout</option>
          <option value="Onne">Onne</option>
          <option value="Mgbuoba">Mgbuoba</option>
          <option value="Rumuolumeni Road">Rumuolumeni Road</option>
          <option value="GRA Phase 2">GRA Phase 2</option>
          <option value="Rumuodara Junction">Rumuodara Junction</option>
          <option value="Rumuibekwe Road">Rumuibekwe Road</option>
          <option value="Uniport">Uniport</option>
          <option value="Rukpokwu">Rukpokwu Roundabout</option>
          <option value="Elelenwo">Elelenwo</option>
          <option value="Old GRA">Old GRA</option>
          <option value="Ikwerre Road">Ikwerre Road</option>
        </select>
      </div>

      {/* Hero Banner */}
      <section className="hero">
        <h1>Welcome To Market Square</h1>
        <p>Your favourite neighborhood supermarket</p>
        <div className="hero-buttons">
          <button className="btn btn-primary" onClick={() => navigate('/shop')}>Shop Now</button>
          <button className="btn btn-secondary">Today's Deals</button>
        </div>
      </section>

      {/* User Guide */}
      <section className="user-guide">
        <h2> New Here?</h2>
        <p>Choose your store, explore products, add items to cart and checkout seamlessly!</p>
      </section>

{/* What We Offer */}

  {/*<section className="services">
    <h2>What We Offer</h2>
    <div className="service-list">*/}
  <section className="services">
    <h2>What We Offer</h2>
    <div className="service-list">
      {[
        { name: 'Air Freshener', img: 'Airfreshern.jpg.jpg', id: 1 },
        { name: 'Milo', img: 'Milo.jpg.jpg', id: 2 },
        { name: 'Four Cousins', img: 'C:\Users\Osaroekaa Sampson\OneDrive\Desktop\e-commerce\public\images\FourCoursinsWhite.jpg.jpg', id: 3 },
        { name: 'Glacondi', img: 'WhatsApp Imag.jpg', id: 4 },
        { name: 'Declan', img: 'WhatsApp Image 2025-05-17 at 22.21.57_5a97a3a7.jpg', id: 5 },
        { name: 'Pressing Iron', img: 'WhatsApp Image 2025-05-17 at 22.21.58_8b75d0a9.jpg', id: 6 },
        { name: 'Bread', img: 'WhatsApp Image 2025-05-17 at 22.21.58_66d918a4.jpg', id: 7 },
        { name: 'Carli Rosy', img: 'WhatsApp Image 2025-05-17 at 22.21.58_8937a717.jpg', id: 8 },
        { name: 'Cliper', img: 'WhatsApp Image 2025-05-17 at 22.21.59_2dce1e0f.jpg', id: 9 },
        { name: 'Fan', img: 'WhatsApp Image 2025-05-17 at 22.22.00_67579d1c.jpg', id: 10 },
        { name: 'Sun Light', img: 'WhatsApp Image 2025-05-17 at 22.22.05_c7c53708.jpg', id: 11 },
        { name: 'Hypo', img: 'WhatsApp Image 2025-05-17 at 22.22.04_ec87568c.jpg', id: 12 },
        { name: 'Klin', img: 'WhatsApp Image 2025-05-17 at 22.22.04_38f0be33.jpg', id: 13 },
        { name: 'Morning Fresh', img: 'WhatsApp Image 2025-05-17 at 22.22.03_f9e9ddad.jpg', id: 14 },
        { name: 'Ariel', img: 'WhatsApp Image 2025-05-17 at 22.22.03_b5adc5b1.jpg', id: 15 },
        { name: 'Blender', img: 'WhatsApp Image 2025-05-17 at 22.22.00_e280a9bb.jpg', id: 16 }
      ].map(item => (
        <div key={item.id} className="service-item" onClick={() => goToProduct(item.id)}>
          <img src={`/images/${item.img}`} alt={item.name} />
          <h4>{item.name}</h4>
        </div>
      ))}
    </div>
  </section>


      {/* Featured Promotions */}
      <section className="promotions">
        <h2>Featured Promotions</h2>
        <div className="promotion-list">
          {featuredPromotions.map(promo => (
            <div key={promo.id} className="promotion-card">
              <h4>{promo.title}</h4>
              <p>{promo.description}</p>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}

export default Home;
